void ZopfliLZ77Greedy(ZopfliBlockState *s, const unsigned char *in,
                      size_t instart, size_t inend,
                      ZopfliLZ77Store *store, ZopfliHash *h)
{
    size_t i = 0, j;
    unsigned short leng;
    unsigned short dist;
    int lengthscore;
    size_t windowstart = instart > ZOPFLI_WINDOW_SIZE
                             ? instart - ZOPFLI_WINDOW_SIZE
                             : 0;
    unsigned short dummysublen[259];

    /* Lazy matching. */
    unsigned prev_length = 0;
    unsigned prev_match = 0;
    int prevlengthscore;
    int match_available = 0;

    if (instart == inend)
        return;

    ZopfliResetHash(ZOPFLI_WINDOW_SIZE, h);
    ZopfliWarmupHash(in, windowstart, inend, h);
    for (i = windowstart; i < instart; i++)
    {
        ZopfliUpdateHash(in, i, inend, h);
    }

    for (i = instart; i < inend; i++)
    {
        ZopfliUpdateHash(in, i, inend, h);

        ZopfliFindLongestMatch(s, h, in, i, inend, ZOPFLI_MAX_MATCH, dummysublen,
                               &dist, &leng);
        lengthscore = GetLengthScore(leng, dist);

        /* Lazy matching. */
        prevlengthscore = GetLengthScore(prev_length, prev_match);
        if (match_available)
        {
            match_available = 0;
            if (lengthscore > prevlengthscore + 1)
            {
                ZopfliStoreLitLenDist(in[i - 1], 0, i - 1, store);
                if (lengthscore >= ZOPFLI_MIN_MATCH && leng < ZOPFLI_MAX_MATCH)
                {
                    match_available = 1;
                    prev_length = leng;
                    prev_match = dist;
                    continue;
                }
            }
            else
            {
                /* Add previous to output. */
                leng = prev_length;
                dist = prev_match;
                lengthscore = prevlengthscore;
                /* Add to output. */
                ZopfliVerifyLenDist(in, inend, i - 1, dist, leng);
                ZopfliStoreLitLenDist(leng, dist, i - 1, store);
                for (j = 2; j < leng; j++)
                {
                    assert(i < inend);
                    i++;
                    ZopfliUpdateHash(in, i, inend, h);
                }
                continue;
            }
        }
        else if (lengthscore >= ZOPFLI_MIN_MATCH && leng < ZOPFLI_MAX_MATCH)
        {
            match_available = 1;
            prev_length = leng;
            prev_match = dist;
            continue;
        }
        /* End of lazy matching. */

        /* Add to output. */
        if (lengthscore >= ZOPFLI_MIN_MATCH)
        {
            ZopfliVerifyLenDist(in, inend, i, dist, leng);
            ZopfliStoreLitLenDist(leng, dist, i, store);
        }
        else
        {
            leng = 1;
            ZopfliStoreLitLenDist(in[i], 0, i, store);

